// ===========================================
// W3: Daily Summary Reporter
// ===========================================
// Queries today's quest completion data from Plane.so,
// calculates stats, sends summary to LobeHub.
// Non-critical — failure is logged but does not affect system.

const https = require('https');
const _fetch = (url, opts = {}, body) => new Promise((ok, fail) => {
  const r = https.request(url, { method: opts.method || 'GET', headers: opts.headers, timeout: opts.timeout || 30000 }, (res) => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => {
      if (res.statusCode >= 400) return fail(new Error(`HTTP ${res.statusCode}: ${d.substring(0,300)}`));
      try { ok(JSON.parse(d)); } catch { ok(d); }
    });
  });
  r.on('error', fail);
  r.on('timeout', () => { r.destroy(); fail(new Error('timeout')); });
  if (body) r.write(typeof body === 'string' ? body : JSON.stringify(body));
  r.end();
});


const config = {
  base_url: $env.PULSE_PLANE_BASE_URL,
  workspace_slug: $env.PULSE_PLANE_WORKSPACE_SLUG,
  api_key: $env.PULSE_PLANE_API_KEY,
  daily_quest_project_id: $env.PULSE_DAILY_QUEST_PROJECT_ID,
  lobehub_webhook_url: $env.PULSE_LOBEHUB_WEBHOOK_URL,
  lobehub_api_key: $env.PULSE_LOBEHUB_API_KEY,
};

const basePath = `${config.base_url}/api/v1/workspaces/${config.workspace_slug}`;
const headers = { 'X-API-Key': config.api_key, 'Content-Type': 'application/json' };
const tz = $env.PULSE_USER_TIMEZONE || 'Asia/Seoul';
const DRY_RUN = ($env.PULSE_DRY_RUN || 'false').toLowerCase() === 'true' || ($env.PULSE_DRY_RUN || 'false') === '1';

const toLocalISO = () => {
  const now = new Date();
  const local = new Date(now.toLocaleString('en-US', { timeZone: tz }));
  const diff = Math.round((local.getTime() - now.getTime()) / 60000);
  const sign = diff >= 0 ? '+' : '-';
  const absH = String(Math.floor(Math.abs(diff) / 60)).padStart(2, '0');
  const absM = String(Math.abs(diff) % 60).padStart(2, '0');
  return local.toISOString().replace('Z', `${sign}${absH}:${absM}`);
};

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const MAX_RETRIES = 3;
const RETRY_MS = 5000;
const withRetry = async (fn, ctx) => {
  for (let i = 1; i <= MAX_RETRIES; i++) {
    try { return await fn(); } catch (e) {
      console.log(`[RETRY] ${ctx} attempt ${i}/${MAX_RETRIES}: ${e.message}`);
      if (i === MAX_RETRIES) throw e;
      await sleep(RETRY_MS);
    }
  }
};

const apiGet = async (path) => {
  return await _fetch(`${basePath}${path}`, { headers });
};

try {
  const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });
  const dayName = new Date().toLocaleDateString('en-US', { timeZone: tz, weekday: 'long' });
  const projId = config.daily_quest_project_id;

  // Fetch today's quests
  const result = await withRetry(
    () => apiGet(`/projects/${projId}/issues/?per_page=100&expand=labels,state&target_date=${todayStr}`),
    'Fetch today quests'
  );
  const quests = result.results || result || [];

  // Calculate stats
  let total = quests.length;
  let completed = 0, deferred = 0, canceled = 0;

  for (const q of quests) {
    const state = q.state_detail?.name || '';
    if (state === 'Done') completed++;
    else if (state === 'Deferred') deferred++;
    else if (state === 'Canceled') canceled++;
  }

  const rate = total > 0 ? Math.round((completed / total) * 100) : 0;

  // Progress message based on completion rate
  let progressMsg = '';
  if (rate >= 90) progressMsg = 'Outstanding day! Almost everything done.';
  else if (rate >= 70) progressMsg = 'Great day! Solid progress.';
  else if (rate >= 50) progressMsg = 'Decent effort. Keep the momentum going!';
  else if (rate >= 30) progressMsg = 'Slow day. Tomorrow is a fresh start.';
  else if (total > 0) progressMsg = 'Tough day. Rest up and try again tomorrow.';
  else progressMsg = 'No quests today. Enjoy the break!';

  // Build summary message
  let summary = `\uD83C\uDFAF Daily Summary — ${todayStr} (${dayName}): ${completed}/${total} (${rate}%)\n\n`;
  summary += `  \u2705 Completed: ${completed}\n`;
  if (deferred > 0) summary += `  \u23F8\uFE0F Deferred: ${deferred}\n`;
  if (canceled > 0) summary += `  \uD83D\uDEAB Canceled: ${canceled}\n`;
  summary += `\n${progressMsg}`;

  // Send to LobeHub
  if (DRY_RUN) {
    console.log(`[DRY_RUN] Would push daily summary to LobeHub:\n${summary}`);
    return [{ json: {
      success: true,
      data: { summary, total, completed, deferred, canceled, rate, dry_run: true },
      error: null,
      metadata: { step: 'w3_daily_summary', timestamp: toLocalISO(), dry_run: true }
    }}];
  }

  if (!config.lobehub_webhook_url) {
    console.log('[WARN] PULSE_LOBEHUB_WEBHOOK_URL not configured. Skipping push.');
    return [{ json: {
      success: true,
      data: { summary, total, completed, deferred, canceled, rate, push_skipped: true },
      error: null,
      metadata: { step: 'w3_daily_summary', timestamp: toLocalISO() }
    }}];
  }

  try {
    const pushHeaders = { 'Content-Type': 'application/json' };
    if (config.lobehub_api_key) {
      pushHeaders['X-API-Key'] = config.lobehub_api_key;
    }

    await withRetry(
      async () => {
        const data = await _fetch(config.lobehub_webhook_url, { method: 'POST', headers: pushHeaders }, {
            action: 'push',
            message: summary,
            source: 'w3-daily-summary'
          });
          return data;
      },
      'Push to LobeHub'
    );
  } catch (pushError) {
    console.log(`[WARN] [LOBEHUB_PUSH_FAILED] ${pushError.message}`);
    // Non-critical — log but don't fail
  }

  return [{ json: {
    success: true,
    data: { summary, total, completed, deferred, canceled, rate },
    error: null,
    metadata: { step: 'w3_daily_summary', timestamp: toLocalISO(), dry_run: false }
  }}];
} catch (e) {
  // W3 failure is non-critical
  console.log(`[ERROR] [W3] ${e.message}`);
  return [{ json: {
    success: false,
    data: null,
    error: { code: 'PLANE_API_ERROR', message: e.message },
    metadata: { step: 'w3_daily_summary', timestamp: toLocalISO() }
  }}];
}
